  padding: 40px 20px;
}

header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 30px;
}

h1 {
  margin: 0;
  font-size: 28px;
  font-weight: 700;
  color: var(--text-color);
}

.reset-btn {
  background-color: var(--primary-color);
  color: white;
  border: none;
  padding: 10px 20px;
  border-radius: 6px;
  font-size: 14px;
  font-weight: 600;
  cursor: pointer;
  transition: background-color 0.2s ease;
}

.reset-btn:hover {
  background-color: var(--primary-hover);
}

.board {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 20px;
  align-items: start;
}

.column {
  background-color: var(--board-bg);
  border-radius: 8px;
  padding: 16px;
  box-shadow: var(--shadow-sm);
  min-height: 400px;
  display: flex;
  flex-direction: column;
}

.column-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 16px;
  padding-bottom: 8px;
}

.column-title {
  margin: 0;
  font-size: 16px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.column[data-column="todo"] .column-title {
  color: var(--todo-border);
}

.column[data-column="doing"] .column-title {
  color: var(--doing-border);
}

.column[data-column="done"] .column-title {
  color: var(--done-border);
}

.card-count {
  background-color: rgba(9, 30, 66, 0.08);
  color: var(--text-muted);
  font-size: 12px;
  font-weight: 600;
  padding: 2px 8px;
  border-radius: 10px;
}

.cards-container {
  display: flex;
  flex-direction: column;
  gap: 12px;
  flex-grow: 1;
  min-height: 150px;
}

.card {
  background-color: var(--card-bg);
  border-radius: 6px;
  padding: 14px;
  box-shadow: var(--shadow-sm);
  cursor: grab;
  transition: transform 0.15s ease, box-shadow 0.15s ease;
  user-select: none;
}

.card:hover {
  box-shadow: var(--shadow-md);
  transform: translateY(-2px);
}

.card:active {
  cursor: grabbing;
}

.column[data-column="todo"] .card {
  border-left: 4px solid var(--todo-border);
}

.column[data-column="doing"] .card {
  border-left: 4px solid var(--doing-border);
}

.column[data-column="done"] .card {
  border-left: 4px solid var(--done-border);
}

.card-id {
  font-size: 11px;
  color: var(--text-muted);
  margin-bottom: 6px;
  font-weight: 600;
}

.card-title {
  font-size: 14px;
  font-weight: 500;
  line-height: 1.4;
  word-break: break-word;
}

/* Responsive */
@media (max-width: 768px) {
  .board {
    grid-template-columns: 1fr;
  }
}

import { component$, useStore, useTask$, $, type QRL } from '@builder.io/qwik';
import { routeLoader$, type DocumentHead } from '@builder.io/qwik-city';
import { getBoard } from '../lib/db';

export const useBoardLoader = routeLoader$(() => {
  return getBoard();
});

export default component$(() => {
  const boardLoader = useBoardLoader();

  const state = useStore({
    todo: boardLoader.value.todo,
    doing: boardLoader.value.doing,
    done: boardLoader.value.done,
    draggingCardId: null as number | null,
  }, { deep: true });

  // Keep store in sync if loader value changes on navigation/reload
  useTask$(({ track }) => {
    const board = track(() => boardLoader.value);
    state.todo = board.todo;
    state.doing = board.doing;
    state.done = board.done;
  });

  const handleMove = $(async (cardId: number, toColumn: 'todo' | 'doing' | 'done', toIndex: number) => {
    // 1. Optimistic UI update
    let foundCard: any = null;
    let fromColumn: 'todo' | 'doing' | 'done' | null = null;

    for (const col of ['todo', 'doing', 'done'] as const) {
      const idx = state[col].findIndex((c: any) => c.id === cardId);
      if (idx !== -1) {
        foundCard = state[col][idx];
        fromColumn = col;
        state[col].splice(idx, 1);
        break;
      }
    }

    if (!foundCard || !fromColumn) return;

    // Insert into target column
    const targetColCards = state[toColumn];
    const clampedIndex = Math.max(0, Math.min(toIndex, targetColCards.length));
    targetColCards.splice(clampedIndex, 0, foundCard);

    // Re-number positions
    for (const col of ['todo', 'doing', 'done'] as const) {
      state[col].forEach((c: any, idx: number) => {
        c.position = idx;
      });
    }

    // 2. Persist to server
    try {
      const res = await fetch('/api/move', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ cardId, toColumn, toIndex }),
      });

      if (res.ok) {
        const updatedBoard = await res.json();
        state.todo = updatedBoard.todo;
        state.doing = updatedBoard.doing;
        state.done = updatedBoard.done;
      } else {
        console.error('Failed to persist move', await res.text());
      }
    } catch (err) {
      console.error('Error persisting move', err);
    }
  });

  const handleReset = $(async () => {
    try {
      const res = await fetch('/api/reset', {
        method: 'POST',
      });
      if (res.ok) {
        const updatedBoard = await res.json();
        state.todo = updatedBoard.todo;
        state.doing = updatedBoard.doing;
        state.done = updatedBoard.done;
      }
    } catch (err) {
      console.error('Error resetting board', err);
    }
  });

  return (
    <div class="app-container">
      <header>
        <h1>Kanban Board</h1>
        <button class="reset-btn" onClick$={handleReset}>
          Reset Board
        </button>
      </header>

      <div class="board">
        {(['todo', 'doing', 'done'] as const).map((colName) => {
          const colCards = state[colName] || [];
          return (
            <div
              key={colName}
              data-column={colName}
              class="column"
              preventdefault:dragover
              preventdefault:drop
              onDragOver$={() => {}}
              onDrop$={() => {
                if (state.draggingCardId !== null) {
                  handleMove(state.draggingCardId, colName, colCards.length);
                }
                state.draggingCardId = null;
              }}
            >
              <div class="column-header">
                <h2 class="column-title">{colName}</h2>
                <span class="card-count">{colCards.length}</span>
              </div>
              <div class="cards-container">
                {colCards.map((card) => (
                  <div
                    key={card.id}
                    data-card-id={card.id}
                    draggable={true}
                    onDragStart$={() => {
                      state.draggingCardId = card.id;
                    }}
                    preventdefault:dragover
                    preventdefault:drop
                    stoppropagation:drop
                    onDragOver$={() => {}}
                    onDrop$={() => {
                      if (state.draggingCardId !== null && state.draggingCardId !== card.id) {
                        handleMove(state.draggingCardId, colName, card.position);
                      }
                      state.draggingCardId = null;
                    }}
                    class="card"
                  >
                    <div class="card-id">#{card.id}</div>
                    <div class="card-title">{card.title}</div>
                  </div>
                ))}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
});

export const head: DocumentHead = {
  title: "Qwik Kanban Board",
  meta: [
    {
      name: "description",
      content: "A native drag-and-drop Kanban Board built with Qwik City and SQLite",
    },
  ],
};

